document.addEventListener("DOMContentLoaded",()=>{const header=document.querySelector("header");let scrollPos=0;let ticking=false;function updateHeader(){if(scrollPos>80){header.classList.add("scrolled")}else{header.classList.remove("scrolled")}ticking=false}window.addEventListener("scroll",()=>{scrollPos=window.scrollY;if(!ticking){window.requestAnimationFrame(updateHeader);ticking=true}},{passive:true});const mobileToggle=document.querySelector(".mobile-toggle");const navLinks=document.querySelector(".nav-links");if(mobileToggle){mobileToggle.addEventListener("click",()=>{const icon=mobileToggle.querySelector("i");navLinks.classList.toggle("active");if(navLinks.classList.contains("active")){icon.classList.replace("fa-bars","fa-times");navLinks.style.display="flex";navLinks.style.flexDirection="column";navLinks.style.position="absolute";navLinks.style.top="100%";navLinks.style.left="0";navLinks.style.width="100%";navLinks.style.background="white";navLinks.style.padding="40px";navLinks.style.boxShadow="0 10px 15px rgba(0,0,0,0.1)";navLinks.querySelectorAll("a").forEach(a=>{a.style.color="#1E3A8A";a.style.fontSize="1.2rem";a.style.textAlign="center"})}else{icon.classList.replace("fa-times","fa-bars");navLinks.style.display=""}})}const revealElements=document.querySelectorAll("[data-reveal]");const revealObserver=new IntersectionObserver(entries=>{entries.forEach(entry=>{if(entry.isIntersecting){entry.target.classList.add("revealed");revealObserver.unobserve(entry.target)}})},{threshold:.15});revealElements.forEach(el=>revealObserver.observe(el));const counterElements=document.querySelectorAll(".counter-num");const countTo=element=>{const target=+element.getAttribute("data-target");let count=0;const duration=2e3;const incrementValue=target/(duration/16);const updateCount=()=>{count+=incrementValue;if(count<target){element.innerText=Math.ceil(count);requestAnimationFrame(updateCount)}else{element.innerText=target}};updateCount()};const counterObserver=new IntersectionObserver(entries=>{entries.forEach(entry=>{if(entry.isIntersecting){countTo(entry.target);counterObserver.unobserve(entry.target)}})},{threshold:.8});counterElements.forEach(el=>counterObserver.observe(el));document.querySelectorAll('a[href^="#"]').forEach(anchor=>{anchor.addEventListener("click",function(e){e.preventDefault();const targetId=this.getAttribute("href");if(targetId==="#")return;const target=document.querySelector(targetId);if(target){window.scrollTo({top:target.offsetTop-100,behavior:"smooth"});if(navLinks.classList.contains("active")){mobileToggle.click()}}})})});